export interface AlphabetChar {
  character?: string
  char?: string
  romanization?: string
  name?: string
  pronunciation: string
  example?: string
  [key: string]: unknown
}

export interface NumberEntry {
  digit?: number | string
  numeral?: string | number
  word: string
  pronunciation: string
}

export interface ConjugationRow {
  pronoun: string
  form: string
  pronunciation?: string
  meaning?: string
}

export interface ConjugationTable {
  verb?: string
  tense?: string
  meaning?: string
  rows: ConjugationRow[]
}

export interface GrammarRule {
  title?: string
  rule?: string
  detail?: string
  explanation?: string
  example?: { english: string; native: string }
}

export interface Idiom {
  expression: string
  literal: string
  meaning: string
  usage: string
}

export interface Proverb {
  text: string
  translation: string
  meaning: string
}

export interface LanguagePillar {
  // Meta
  language: string
  slug: string
  nativeName: string
  flag: string
  speakers: string
  nativeSpeakers: string
  family: string
  branch: string
  script: string
  writingDirection: 'ltr' | 'rtl' | 'ttb'
  difficulty: 'Easy' | 'Medium' | 'Hard' | 'Very Hard'
  difficultyScore: number
  officialIn: string[]
  description: string
  funFacts: string[]
  whyLearn: string[]
  translatorLink: string
  reverseLink: string
  phrasesLink: string
  vocabularyLink: string
  learnLink: string

  // Alphabet tab
  alphabetIntro: string
  alphabet: AlphabetChar[]

  // Numbers tab
  numbers: NumberEntry[]
  daysOfWeek?: ({ english: string; native: string; pronunciation: string } | { day: string; translation: string; pronunciation: string } | { english: string; translation: string; pronunciation: string; word: string } | { day: string; translation: string; pronunciation: string; word: string })[]
  months?: ({ english: string; native: string; pronunciation: string } | { month: string; translation: string; pronunciation: string } | { english: string; translation: string; pronunciation: string; word: string } | { month: string; translation: string; pronunciation: string; word: string })[]

  // Grammar tab
  sentenceStructure: string
  sentenceExample: { english: string; native?: string; breakdown: string | Array<{ word: string; meaning: string }> } & Record<string, unknown>
  grammarRules: GrammarRule[]
  conjugationTables: ConjugationTable[]

  // Idioms tab
  idioms: Idiom[]
  proverbs: Proverb[]
}

