// Index for generateStaticParams and lookups
export const languagePillarIndex = languagePillarData.map((l) => ({
  slug: l.slug,
  language: l.language,
  flag: l.flag,
  nativeName: l.nativeName,
  speakers: l.speakers,
  difficulty: l.difficulty,
  script: l.script,
}))

export function getLanguagePillarBySlug(slug: string): LanguagePillar | undefined {
  return languagePillarData.find((l) => l.slug === slug)
}
